const limit = 10;
const endpoint = `https://amadeus-pig-tracking-system.onrender.com/api/reports/farm-attention-summary?limit=${limit}`;

return [{
  json: {
    request_url: endpoint,
    limit,
    notes: "Read-only farm attention summary. Delivery safety is handled after backend response validation.",
  },
}];

const dryRun = true;
const forceSend = false;
const minHoursBetweenSends = 20;

function stableStringify(value) {
  if (Array.isArray(value)) return `[${value.map(stableStringify).join(",")}]`;
  if (value && typeof value === "object") {
    return `{${Object.keys(value).sort().map((key) => `${JSON.stringify(key)}:${stableStringify(value[key])}`).join(",")}}`;
  }
  return JSON.stringify(value);
}

function hashText(value) {
  const text = stableStringify(value);
  let hash = 5381;
  for (let i = 0; i < text.length; i += 1) {
    hash = ((hash << 5) + hash) + text.charCodeAt(i);
    hash |= 0;
  }
  return String(hash >>> 0);
}

function hoursBetween(a, b) {
  return Math.abs(b.getTime() - a.getTime()) / 36e5;
}

const response = $json || {};
const source = response.source && typeof response.source === "object" ? response.source : {};

if (response.success !== true || response.status !== "ok") return [];
if (response.mode !== "read_only") return [];
if (source.writes_to_supabase === true || source.writes_to_sheets === true || source.sends_telegram === true) return [];

const counts = response.counts && typeof response.counts === "object" ? response.counts : {};
const attentionTotal = Number(counts.attention_total || 0);
if (!Number.isFinite(attentionTotal) || attentionTotal <= 0) return [];

const digestLines = Array.isArray(response.digest_lines) ? response.digest_lines : [];
if (digestLines.length === 0) return [];

const contentHash = hashText({
  report_date: response.report_date,
  counts,
  digest_lines: digestLines,
});

const staticData = $getWorkflowStaticData("global");
const now = new Date();
const lastSentAt = staticData.lastSentAt ? new Date(staticData.lastSentAt) : null;
const recentlySent = lastSentAt && !Number.isNaN(lastSentAt.getTime()) && hoursBetween(lastSentAt, now) < minHoursBetweenSends;
const sameContent = staticData.lastSentHash === contentHash;

if (dryRun) return [];
if (!forceSend && sameContent) return [];
if (!forceSend && recentlySent) return [];

return [{
  json: {
    report_date: response.report_date,
    generated_at: response.generated_at,
    counts,
    digest_lines: digestLines,
    content_hash: contentHash,
    dry_run: dryRun,
    force_send: forceSend,
    min_hours_between_sends: minHoursBetweenSends,
    source,
  },
}];

const CHARL_TELEGRAM_CHAT_ID = "5721652188";

function clean(value) {
  return String(value ?? "").trim();
}

function formatDate(value) {
  if (!value) return "today";
  const d = new Date(`${value}T00:00:00+02:00`);
  if (Number.isNaN(d.getTime())) return value;
  return new Intl.DateTimeFormat("en-ZA", {
    timeZone: "Africa/Johannesburg",
    year: "numeric",
    month: "short",
    day: "2-digit",
  }).format(d);
}

return $input.all().map((item) => {
  const digest = item.json || {};
  const counts = digest.counts || {};
  const lines = Array.isArray(digest.digest_lines) ? digest.digest_lines.map(clean).filter(Boolean) : [];
  const text = [
    `Farm attention digest - ${formatDate(digest.report_date)}`,
    "",
    `Total: ${counts.attention_total || 0}`,
    `Orders: ${counts.orders_needing_attention || 0}`,
    `Litters: ${counts.litter_attention || 0}`,
    "",
    ...lines.slice(0, 25),
  ].join("\n");

  return {
    json: {
      chatId: CHARL_TELEGRAM_CHAT_ID,
      telegram_text: text,
      report_date: digest.report_date,
      content_hash: digest.content_hash,
      counts,
      _digest: digest,
    },
  };
});

const now = new Date();
const staticData = $getWorkflowStaticData("global");

return $input.all().map((item) => {
  const payload = item.json || {};
  if (payload.content_hash) {
    staticData.lastSentAt = now.toISOString();
    staticData.lastSentHash = payload.content_hash;
    staticData.lastReportDate = payload.report_date || "";
  }

  return {
    json: {
      ...payload,
      delivery_recorded_at: now.toISOString(),
      delivery_static_data_note: "Duplicate suppression state is recorded after Telegram delivery succeeds. Manual executions may not persist workflow static data in n8n.",
    },
  };
});
